if (! function_exists('whois_lookup')) {
    function whois_lookup($domain, $server = null, $timeout = null, $parse = null)
    {
            $domain = $domain ?? '';
            $server = $server ?? '';
            $timeout = $timeout ?? 15;
            $parse = $parse ?? true;

            $timeout = max(5, min(30, (int)$timeout));
            $domain = trim(strtolower($domain));

            if (empty($domain)) {
                return ['success' => false, 'error' => 'Domain name is required.'];
            }

            // Strip protocol and path if a URL was passed
            $domain = preg_replace('#^https?://#', '', $domain);
            $domain = preg_replace('#/.*$#', '', $domain);
            // Strip port if present
