                'fi' => 'whois.fi',
                'ie' => 'whois.iedr.ie',
                'pt' => 'whois.dns.pt',
            ];

            // Helper: WHOIS query via TCP socket
            $do_whois = function($query_domain, $whois_server, $t) {
                $errno = 0;
                $errstr = '';
                $socket = @fsockopen($whois_server, 43, $errno, $errstr, $t);
                if (!$socket) {
                    return ['success' => false, 'error' => "Socket connection failed: $errstr ($errno)"];
                }
                // Set read timeout
                stream_set_timeout($socket, $t);
                // Send query per WHOIS protocol
                $query = $query_domain . "\r\n";
                if (@fwrite($socket, $query) === false) {
                    fclose($socket);
                    return ['success' => false, 'error' => 'Failed to send WHOIS query.'];
                }
                // Read response
                $response = '';
                while (!feof($socket)) {
                    $chunk = @fread($socket, 8192);
                    if ($chunk === false) break;
                    $response .= $chunk;
                    // Check for timeout
                    $meta = stream_get_meta_data($socket);
                    if ($meta['timed_out']) {
                        fclose($socket);
                        return ['success' => false, 'error' => 'WHOIS server timed out.'];
                    }
                }
                fclose($socket);

                if (empty(trim($response))) {
                    return ['success' => false, 'error' => 'Empty response from WHOIS server.'];
                }

                return ['success' => true, 'raw' => $response];
            };

            // Determine target WHOIS server
            $target_server = $server;
            if (empty($target_server)) {
                $target_server = $whois_servers[$tld] ?? '';
                if (empty($target_server)) {
                    // Try IANA lookup for unknown TLDs
                    $iana = $do_whois($tld, 'whois.iana.org', $timeout);
                    if ($iana['success']) {
