                $lines = explode("\n", $raw);
                $current_section = '';
                foreach ($lines as $line) {
                    $trimmed = trim($line);
                    // Detect section headers
                    if (preg_match('/^([A-Z][A-Za-z\s]+):$/m', $trimmed, $sm)) {
                        $current_section = trim($sm[1]);
                        continue;
                    }
                    // Parse key: value
                    if (preg_match('/^([A-Za-z][\w\s\-\.]+?):\s*(.*)$/m', $trimmed, $m)) {
                        $key = trim($m[1]);
                        $value = trim($m[2]);
                        if (!empty($value)) {
                            // Group by section if we're in one
                            if (!empty($current_section)) {
                                $parsed[$current_section][$key] = $value;
                            } else {
                                $parsed[$key] = $value;
                            }
                        }
                    }
                }
            }

            // Extract useful individual fields for quick access
            $quick = [];
            $field_map = [
                'Domain Name' => 'domain_name',
