            foreach ($field_map as $whois_key => $short_key) {
                $val = null;
                // Search in flat parsed
                if (isset($parsed[$whois_key])) {
                    $val = $parsed[$whois_key];
                }
                // Search in sections
                foreach ($parsed as $section => $fields) {
                    if (is_array($fields) && isset($fields[$whois_key])) {
                        $val = $fields[$whois_key];
                        break;
                    }
                }
                if ($val !== null) {
                    $quick[$short_key] = $val;
                }
            }

